<?php require_once __DIR__ . '/app/auth.php'; if (is_logged_in()) redirect('index.php'); $error=''; if ($_SERVER['REQUEST_METHOD']==='POST') { $u=trim($_POST['username'] ?? ''); $p=$_POST['password'] ?? ''; $stmt=db()->prepare('SELECT * FROM users WHERE username=? LIMIT 1'); $stmt->execute([$u]); $user=$stmt->fetch(); if ($user && password_verify($p, $user['password_hash'])) { $_SESSION['user']=['id'=>$user['id'],'name'=>$user['name'],'username'=>$user['username'],'role'=>$user['role']]; redirect('index.php'); } $error='Username atau password belum sesuai.'; } ?>
<!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Login - Dentanet Billing</title><script src="https://cdn.tailwindcss.com"></script><link rel="stylesheet" href="assets/style.css"></head><body class="app-body"><section class="login-page"><div class="login-card"><div class="login-hero"><img src="assets/dentanet-logo.png" alt="Dentanet"><h1>Billing internet yang terang, cepat, siap dipakai.</h1><p>Kelola pelanggan, paket, pembayaran, status ON/OFF, dan laporan pemasukan dari satu aplikasi operasional Dentanet.</p></div><form class="login-form" method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><h2>Login Admin</h2><p class="text-slate-500 mb-5">Masukkan akun operator. Kredensial tidak ditampilkan di halaman.</p><?php if($error):?><div class="notice err"><?=e($error)?></div><?php endif;?><div class="field mb-4"><label>Username</label><input name="username" required autocomplete="username" autofocus></div><div class="field mb-5"><label>Password</label><input name="password" required type="password" autocomplete="current-password"></div><button class="btn primary w-full" type="submit">Masuk Dashboard</button></form></div></section></body></html>
